const lead = $('Check Sales Memo Eligible').item.json;
const fallbackMemo = {
  company_background: [],
  talking_points: [],
  pain_hypotheses: [],
  recommended_opener: (lead.content_summary || 'Review lead summary before outreach.').slice(0, 300),
